using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10m * i,
                Quantity = i
            })
            .ToList();

    [TestMethod]
    public void CreateOrder_WithValidInputs_ReturnsOrderWithCorrectCustomerId()
    {
        // Arrange
        var customerId = "cust-123";
        var items = CreateItems();

        // Act
        var order = _sut.CreateOrder(customerId, items);

        // Assert
        Assert.AreEqual(customerId, order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidInputs_AssignsNonEmptyId()
    {
        // Arrange
        var items = CreateItems();

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 3 },
            new() { ProductName = "Gadget", Price = 12.50m, Quantity = 2 },
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert — (5*3) + (12.50*2) = 15 + 25 = 40
        Assert.AreEqual(40.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_SetsCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Book", Price = 9.99m, Quantity = 1 }
        };

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual(9.99m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems();

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = CreateItems();

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var emptyItems = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", emptyItems));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var created = _sut.CreateOrder("cust-1", CreateItems());

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        _sut.CreateOrder("cust-A", CreateItems());
        _sut.CreateOrder("cust-A", CreateItems(2));
        _sut.CreateOrder("cust-B", CreateItems());

        // Act
        var orders = _sut.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Arrange
        _sut.CreateOrder("cust-A", CreateItems());

        // Act
        var orders = _sut.GetOrdersByCustomer("cust-Z");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void CreateOrder_CalledMultipleTimes_AssignsUniqueIds()
    {
        // Arrange & Act
        var order1 = _sut.CreateOrder("cust-1", CreateItems());
        var order2 = _sut.CreateOrder("cust-1", CreateItems());

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }
}

